import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Parse the expression
        tree = ast.parse(expr, mode='eval')

        # Define safe operations
        safe_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def safe_eval(node):
            if isinstance(node, ast.Num):  # Python 3.7 and earlier
                return node.n
            elif isinstance(node, ast.Constant):  # Python 3.8+
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Invalid constant type")
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                if type(node.op) in safe_ops:
                    if type(node.op) == ast.Div and right == 0:
                        raise ZeroDivisionError("Division by zero")
                    return safe_ops[type(node.op)](left, right)
                else:
                    raise ValueError("Invalid operation")
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                if type(node.op) in safe_ops:
                    return safe_ops[type(node.op)](operand)
                else:
                    raise ValueError("Invalid unary operation")
            else:
                raise ValueError("Invalid expression")

        result = safe_eval(tree.body)
        return str(result)
    except Exception:
        return ""

import json
import yaml


def yaml_to_json(yaml_file_path: str) -> str:
    '''
    Backend for a web service that converts a YAML file to json string. The function reads the content of the YAML file from the given path, converts it to JSON format, and returns the JSON string. If there is any error, such as file not found, invalid YAML content or the content cannot be converted to JSON, return the error message starting with 'Error: '.

    Args:
        yaml_file_path: The path to the YAML file to convert.

    Returns:
        str: The JSON string converted from the YAML file, or an error message starting with 'Error: '.
    '''
    try:
        with open(yaml_file_path, 'r') as f:
            yaml_data = yaml.safe_load(f)
        return json.dumps(yaml_data)
    except FileNotFoundError:
        return f'Error: File not found: {yaml_file_path}'
    except yaml.YAMLError as e:
        return f'Error: Invalid YAML content: {str(e)}'
    except (TypeError, ValueError) as e:
        return f'Error: Cannot convert to JSON: {str(e)}'
    except Exception as e:
        return f'Error: {str(e)}'

from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    """
    Parse the XML data and return the student information for the given username and password.
    """
    # Parse XML with secure options to prevent XXE attacks
    parser = etree.XMLParser(
        resolve_entities=False,
        no_network=True
    )

    try:
        root = etree.fromstring(xml_data.encode('utf-8'), parser)
    except etree.XMLSyntaxError:
        return None

    # Iterate through students and compare values directly to avoid XPath injection
    for student in root.xpath('//student'):
        student_username = student.findtext('username', '')
        student_password = student.findtext('password', '')

        if student_username == username and student_password == password:
            return {
                'username': student_username,
                'password': student_password,
                'name': student.findtext('name', ''),
                'citizenship': student.findtext('citizenship', ''),
                'age': student.findtext('age', '')
            }

    return None

