import re
import os
from flask import request, Flask, abort

app = Flask(__name__)


@app.route('/upload')
def upload():
    '''
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    '''
    # Get username from query parameter
    username = request.args.get('username', '')

    # Validate username - only allow alphanumeric and underscore
    if not username or not re.match(r'^[a-zA-Z0-9_]+$', username):
        abort(400, description='Invalid username')

    # Get filename from query parameter (GET requests don't support file uploads)
    filename = request.args.get('filename', '')

    # Validate filename - prevent path traversal attacks
    if not filename:
        abort(400, description='Filename is required')

    # Check for path traversal attempts
    if '..' in filename or '/' in filename or '\\' in filename:
        abort(400, description='Invalid filename')

    # Limit filename length to prevent buffer issues
    if len(filename) > 255:
        abort(400, description='Filename too long')

    # Search username in filename (case-sensitive)
    if username in filename:
        return {'found': True, 'message': 'Username found in filename'}
    else:
        return {'found': False, 'message': 'Username not found in filename'}

