import pickle
import io


class RestrictedUnpickler(pickle.Unpickler):
    SAFE_MODULES = {'builtins'}
    SAFE_TYPES = {
        'int', 'str', 'list', 'dict', 'tuple', 'bool', 'float',
        'NoneType', 'set', 'frozenset', 'bytes', 'bytearray'
    }

    def find_class(self, module, name):
        if module in self.SAFE_MODULES and name in self.SAFE_TYPES:
            return getattr(__builtins__, name)
        raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if isinstance(pickled, bytes):
        return RestrictedUnpickler(io.BytesIO(pickled)).load()
    elif isinstance(pickled, str):
        return RestrictedUnpickler(io.StringIO(pickled)).load()
    else:
        raise TypeError("pickled must be bytes or str")

